# -*- coding: utf-8 -*-
"""MiniMax Hailuo Video Generation API"""

import requests
import time
import sys
import os

# Windows UTF-8 support
if sys.platform == "win32":
    os.system("chcp 65001 > nul 2>&1")

class VideoGenerator:
    def __init__(self, api_key):
        self.api_key = api_key
        self.base_url = "https://api.minimax.chat/v1"
        self.headers = {
            "Authorization": f"Bearer {api_key}",
            "Content-Type": "application/json"
        }

    def create_task(self, prompt, model="MiniMax-Hailuo-2.3", video_length=6, resolution="1080p", enable_audio=True):
        url = f"{self.base_url}/video_generation"
        payload = {
            "model": model,
            "prompt": prompt,
            "video_length": video_length,
            "resolution": resolution,
            "enable_audio": enable_audio
        }

        print("[*] Creating video task...")
        print(f"    Model: {model}")
        print(f"    Prompt: {prompt[:100]}...")

        try:
            resp = requests.post(url, headers=self.headers, json=payload)
            result = resp.json()

            if result.get("base_resp", {}).get("status_code") == 0:
                task_id = result.get("task_id")
                print(f"[+] Task created! ID: {task_id}")
                return task_id
            else:
                print(f"[-] Error: {result.get('base_resp', {}).get('status_msg', 'Unknown')}")
                return None
        except Exception as e:
            print(f"[-] Request failed: {e}")
            return None

    def query_status(self, task_id):
        url = f"{self.base_url}/query/video_generation"
        params = {"task_id": task_id}

        try:
            resp = requests.get(url, headers=self.headers, params=params)
            result = resp.json()
            status = result.get("task_status", "Unknown")
            print(f"[*] Status: {status}")
            return result
        except Exception as e:
            print(f"[-] Query failed: {e}")
            return None

    def wait_complete(self, task_id, interval=5, timeout=300):
        print("[*] Waiting for completion...")
        start = time.time()

        while True:
            if time.time() - start > timeout:
                print("[-] Timeout!")
                return None

            result = self.query_status(task_id)
            if not result:
                time.sleep(interval)
                continue

            status = result.get("task_status")

            if status == "Success":
                print("[+] Video generation complete!")
                return result
            elif status == "Failed":
                print(f"[-] Failed: {result.get('error_message', 'Unknown')}")
                return None
            elif status in ["Processing", "Queueing"]:
                progress = result.get("progress", 0)
                print(f"    Processing... {progress}%")
                time.sleep(interval)
            else:
                time.sleep(interval)

    def download_video(self, file_id, output_path=None):
        url = f"{self.base_url}/files/retrieve"
        params = {"file_id": file_id}

        try:
            resp = requests.get(url, headers=self.headers, params=params)
            result = resp.json()

            download_url = result.get("download_url") or result.get("file_url")
            if not download_url:
                print("[-] No download URL found")
                return None

            print(f"[*] Downloading video...")
            video_resp = requests.get(download_url, stream=True)

            if output_path is None:
                output_path = f"video_{file_id}.mp4"

            with open(output_path, "wb") as f:
                for chunk in video_resp.iter_content(chunk_size=8192):
                    f.write(chunk)

            print(f"[+] Downloaded: {output_path}")
            return output_path
        except Exception as e:
            print(f"[-] Download failed: {e}")
            return None

    def generate(self, prompt, model="MiniMax-Hailuo-2.3", video_length=6, resolution="1080p", output=None):
        task_id = self.create_task(prompt, model, video_length, resolution)
        if not task_id:
            return None

        result = self.wait_complete(task_id)
        if not result:
            return None

        file_id = result.get("file_id")
        return self.download_video(file_id, output)


# Presets for koubo videos
KOUBO_PRESETS = {
    "news": {
        "name": "News Anchor",
        "prompt": "Professional news anchor broadcasting news, wearing formal suit, news studio background, professional lighting, HD quality"
    },
    "tutorial": {
        "name": "Tutorial",
        "prompt": "Teacher explaining knowledge, friendly expression, natural hand gestures, educational setting, clear delivery"
    },
    "vlog": {
        "name": "Vlog Style",
        "prompt": "Life blogger sharing daily life, natural expression, relaxed atmosphere, home background, casual style"
    },
    "business": {
        "name": "Business Presentation",
        "prompt": "Business professional presenting product, professional image, confident expression, office setting, formal attire"
    }
}


def main():
    API_KEY = "sk-api-TrutzTosGq8IuE6fvyXQIaMm51474LvuFmSYPvqrz5LjZEMKI6-YAak2QsVFJcslNV9VHlWyJ_pkhjYHSJ_d8jzgmAVe7Q2GROQvvmrhJqUaaz2Zb5dRbLU"
    gen = VideoGenerator(API_KEY)

    print("="*50)
    print("MiniMax Hailuo Video Generator")
    print("="*50)

    # Select preset
    print("\nAvailable presets:")
    for key, preset in KOUBO_PRESETS.items():
        print(f"  [{key}] {preset['name']}")

    preset_key = "business"  # Change this: news, tutorial, vlog, business
    preset = KOUBO_PRESETS[preset_key]

    print(f"\n[*] Using preset: {preset['name']}")

    # Generate
    result = gen.generate(
        prompt=preset['prompt'],
        model="MiniMax-Hailuo-2.3",
        video_length=6,
        resolution="1080p",
        output=f"{preset_key}_koubo.mp4"
    )

    if result:
        print(f"\n[+] SUCCESS! Video saved: {result}")
    else:
        print("\n[-] FAILED!")


if __name__ == "__main__":
    main()

